class SQLQueryInput(BaseModel):
    query: str

    @validator('query')
    def no_dangerous_keywords(cls, v):
        dangerous = ['DROP', 'DELETE', 'TRUNCATE', 'ALTER']
        if any(kw in v.upper() for kw in dangerous):
            raise ValueError(f'Destructive SQL not permitted: {v}')
        return v

@tool(args_schema=SQLQueryInput)
